import os
import pickle
import json
from typing import Union, Dict, Any
import time

class ExpiringCache:
    def __init__(self, cache_dir: str = '.cache', expiration: int = 3600):
        self.cache_dir = cache_dir
        self.expiration = expiration
        self.ensure_directory()

    def ensure_directory(self):
        if not os.path.exists(self.cache_dir):
            os.makedirs(self.cache_dir)

    def get(self, key: str, default=None) -> Union[Dict[str, Any], None]:
        cache_file = self._get_cache_file_path(key)
        if os.path.exists(cache_file):
            with open(cache_file, 'rb') as f:
                data = pickle.load(f)
                timestamp = data['timestamp']
                age = int((time.time() - timestamp))
                if age <= self.expiration:
                    return data['data']
        return default

    def set(self, key: str, data: Dict[str, Any], expire_after: int = None):
        cache_file = self._get_cache_file_path(key)
        timestamp = time.time()
        metadata = {'timestamp': timestamp}
        if expire_after is not None:
            metadata['expiration'] = timestamp + expire_after
        with open(cache_file, 'wb') as f:
            pickle.dump({'data': data, **metadata}, f)

    def _get_cache_file_path(self, key: str) -> str:
        return os.path.join(self.cache_dir, f"{key}.pickle")